/**
 * Phase 9 — Typed factory dispatcher.
 *
 * Looks up a per-orbital factory by (organism, orbitalName) and calls
 * it with consumer params, narrowing from `object` to the per-factory
 * typed shape via emitted typed guards (no `as unknown as`).
 *
 * Autogenerated by almadar-sync std-ts from
 * packages/almadar-std/behaviors/registry/<topic>/organisms/std-*.orb
 * (multi-orbital organisms only).
 *
 * @packageDocumentation
 */

import type { OrbitalDefinition, TraitReference } from '@almadar/core/types';

import {
  stdUiActionPaletteActionPaletteOrbital,
  StdUiActionPaletteActionPaletteOrbitalManifest,
  isStdUiActionPaletteActionPaletteOrbitalParams,
} from './ui/game/organisms/ui-action-palette.js';
import {
  stdUiActionTileActionTileOrbital,
  StdUiActionTileActionTileOrbitalManifest,
  isStdUiActionTileActionTileOrbitalParams,
} from './ui/game/organisms/ui-action-tile.js';
import {
  stdUiSequenceBarSequenceBarOrbital,
  StdUiSequenceBarSequenceBarOrbitalManifest,
  isStdUiSequenceBarSequenceBarOrbitalParams,
} from './ui/game/organisms/ui-sequence-bar.js';
import {
  stdUiSequencerBoardSequencerBoardOrbital,
  StdUiSequencerBoardSequencerBoardOrbitalManifest,
  isStdUiSequencerBoardSequencerBoardOrbitalParams,
} from './ui/game/organisms/ui-sequencer-board.js';
import {
  stdUiTraitSlotTraitSlotOrbital,
  StdUiTraitSlotTraitSlotOrbitalManifest,
  isStdUiTraitSlotTraitSlotOrbitalParams,
} from './ui/game/organisms/ui-trait-slot.js';

export interface ParamFieldDescriptor {
  name: string;
  type: string;
  description: string;
}

export interface OrbitalParamsManifest {
  organism: string;
  orbitalName: string;
  paramFields: readonly ParamFieldDescriptor[];
  traitNames: readonly string[];
  inlineTraitNames: readonly string[];
}

interface DispatchEntry {
  factory: (params: object) => OrbitalDefinition;
  manifest: OrbitalParamsManifest;
}

const REGISTRY: ReadonlyMap<string, DispatchEntry> = new Map<string, DispatchEntry>([
  ['ui-action-palette::ActionPaletteOrbital', {
    factory: (p: object): OrbitalDefinition => {
      if (!isStdUiActionPaletteActionPaletteOrbitalParams(p)) {
        throw new TypeError('Invalid params for ui-action-palette::ActionPaletteOrbital');
      }
      return stdUiActionPaletteActionPaletteOrbital(p);
    },
    manifest: StdUiActionPaletteActionPaletteOrbitalManifest,
  }],
  ['ui-action-tile::ActionTileOrbital', {
    factory: (p: object): OrbitalDefinition => {
      if (!isStdUiActionTileActionTileOrbitalParams(p)) {
        throw new TypeError('Invalid params for ui-action-tile::ActionTileOrbital');
      }
      return stdUiActionTileActionTileOrbital(p);
    },
    manifest: StdUiActionTileActionTileOrbitalManifest,
  }],
  ['ui-sequence-bar::SequenceBarOrbital', {
    factory: (p: object): OrbitalDefinition => {
      if (!isStdUiSequenceBarSequenceBarOrbitalParams(p)) {
        throw new TypeError('Invalid params for ui-sequence-bar::SequenceBarOrbital');
      }
      return stdUiSequenceBarSequenceBarOrbital(p);
    },
    manifest: StdUiSequenceBarSequenceBarOrbitalManifest,
  }],
  ['ui-sequencer-board::SequencerBoardOrbital', {
    factory: (p: object): OrbitalDefinition => {
      if (!isStdUiSequencerBoardSequencerBoardOrbitalParams(p)) {
        throw new TypeError('Invalid params for ui-sequencer-board::SequencerBoardOrbital');
      }
      return stdUiSequencerBoardSequencerBoardOrbital(p);
    },
    manifest: StdUiSequencerBoardSequencerBoardOrbitalManifest,
  }],
  ['ui-trait-slot::TraitSlotOrbital', {
    factory: (p: object): OrbitalDefinition => {
      if (!isStdUiTraitSlotTraitSlotOrbitalParams(p)) {
        throw new TypeError('Invalid params for ui-trait-slot::TraitSlotOrbital');
      }
      return stdUiTraitSlotTraitSlotOrbital(p);
    },
    manifest: StdUiTraitSlotTraitSlotOrbitalManifest,
  }],
]);

/**
 * One trait reference appended via `params.extraTraits[]`. Phase 2
 * (Mechanism 2). `from` + `as` are required because the dispatcher
 * merges into `uses[]` verbatim — no JS-side name transforms.
 * Mirrors `ExtraTraitRef` from @almadar-io/agent — kept structural
 * (no inter-package type dep) but type-compatible.
 */
export interface DispatchExtraTrait
  extends Pick<TraitReference, 'ref' | 'name' | 'linkedEntity' | 'config' | 'events' | 'listens' | 'emitsScope'>
{
  from: string;
  as: string;
}

/**
 * Look up the per-orbital factory by (organism, orbitalName) and call
 * it with the supplied params. Returns null when no factory exists.
 * Throws TypeError when params fail the factory's typed guard
  (caught by the agent's instantiate-orbital surface).
 *
 * `params.extraTraits` (Phase 2) is orthogonal to factory-specific
 * params: it's separated out BEFORE the typed guard runs and appended
 * to `def.traits[]` (with corresponding `uses[]` entries merged) AFTER
 * the factory returns. Strictly additive — never replaces factory
 * traits.
 *
 * `params.traitOverrides` may also carry entries keyed on an
 * extra-trait's NAME (Phase 4's `applyRuleOverlay` row emits
 * `traitOverrides[<TraitName>].config` for capability-matched traits).
 * Those entries are partitioned out BEFORE the typed guard runs — the
 * factory's guard rejects unknown trait keys — and merged into the
 * matching extraTrait BEFORE it's appended. Native-trait overrides
 * (keys in the factory's `manifest.traitNames`) stay on the factory
 * params untouched.
 */
export function dispatchOrbitalFactory(
  organism: string,
  orbitalName: string,
  params: object & { extraTraits?: DispatchExtraTrait[] },
): OrbitalDefinition | null {
  const entry = REGISTRY.get(`${organism}::${orbitalName}`);
  if (!entry) return null;
  const { extraTraits, ...rest } = params;
  const { factoryParams, extraOverrides } = partitionTraitOverrides(
    rest,
    extraTraits ?? [],
    entry.manifest.traitNames,
  );
  const def = entry.factory(factoryParams);
  if (extraTraits && extraTraits.length > 0) {
    if (!def.uses) def.uses = [];
    if (!def.traits) def.traits = [];
    for (const extra of extraTraits) {
      const aliasTaken = def.uses.some((u) => u.as === extra.as);
      if (!aliasTaken) {
        def.uses.push({ from: extra.from, as: extra.as });
      }
      const extraName = extraTraitName(extra);
      const overlay = extraName ? extraOverrides[extraName] : undefined;
      const { from: _from, as: _as, ...traitFields } = extra;
      const merged = overlay
        ? mergeExtraTraitWithOverlay(traitFields, overlay)
        : traitFields;
      def.traits.push(merged);
    }
  }
  return def;
}

/**
 * Returns the trait name carried by an extra-trait entry, used to
 * match a `traitOverrides[<name>]` key onto the trait.
 *
 * Preference order: explicit `name` (the renamed-at-call-site form),
 * else the tail of `ref` ("Alias.traits.TraitName" → "TraitName"). Any
 * other shape returns undefined and the entry inherits no overlay.
 */
function extraTraitName(extra: DispatchExtraTrait): string | undefined {
  if (typeof extra.name === 'string' && extra.name.length > 0) return extra.name;
  const ref = typeof extra.ref === 'string' ? extra.ref : '';
  const match = /\.traits\.([A-Za-z0-9_]+)$/.exec(ref);
  return match?.[1];
}

/**
 * Split the agent-supplied `traitOverrides` dict into the slice the
 * factory accepts (keys that match its manifest's `traitNames`) and
 * the slice keyed on extra-trait names (Phase 4 capability matches).
 *
 * Unknown keys (neither factory-native nor an extra trait) stay on
 * `factoryParams.traitOverrides` so the factory's typed guard surfaces
 * them — they're real authoring bugs we want to see, not silently
 * dropped.
 */
function partitionTraitOverrides(
  rest: { traitOverrides?: Record<string, object> } & object,
  extraTraits: ReadonlyArray<DispatchExtraTrait>,
  factoryTraitNames: ReadonlyArray<string>,
): { factoryParams: object; extraOverrides: Record<string, object> } {
  const overrides = (rest as { traitOverrides?: Record<string, object> }).traitOverrides;
  if (!overrides || typeof overrides !== 'object') {
    return { factoryParams: rest, extraOverrides: {} };
  }
  const factorySet = new Set(factoryTraitNames);
  const extraSet = new Set<string>();
  for (const e of extraTraits) {
    const n = extraTraitName(e);
    if (n) extraSet.add(n);
  }
  const factoryOverrides: Record<string, object> = {};
  const extraOverrides: Record<string, object> = {};
  for (const [k, v] of Object.entries(overrides)) {
    if (extraSet.has(k) && !factorySet.has(k)) {
      extraOverrides[k] = v;
    } else {
      factoryOverrides[k] = v;
    }
  }
  return {
    factoryParams: { ...rest, traitOverrides: factoryOverrides },
    extraOverrides,
  };
}

/**
 * Merge an extra-trait entry with a `traitOverrides[<name>]` overlay
 * lifted from `params.traitOverrides`. The overlay's `config`,
 * `events`, `listens`, `linkedEntity`, `name`, and `emitsScope` keys
 * win; the extra-trait entry's `ref` is preserved (the overlay can't
 * change which atom-side trait we reference).
 */
function mergeExtraTraitWithOverlay(
  trait: Omit<DispatchExtraTrait, 'from' | 'as'>,
  overlay: object,
): Omit<DispatchExtraTrait, 'from' | 'as'> {
  const o = overlay as Partial<DispatchExtraTrait>;
  return {
    ...trait,
    ...(o.config !== undefined ? { config: { ...(trait.config ?? {}), ...o.config } } : {}),
    ...(o.events !== undefined ? { events: { ...(trait.events ?? {}), ...o.events } } : {}),
    ...(o.listens !== undefined ? { listens: o.listens } : {}),
    ...(o.linkedEntity !== undefined ? { linkedEntity: o.linkedEntity } : {}),
    ...(o.name !== undefined ? { name: o.name } : {}),
    ...(o.emitsScope !== undefined ? { emitsScope: o.emitsScope } : {}),
  };
}

/**
 * Fetch the params manifest for one (organism, orbitalName). Returns
 * null when no factory exists. Used by the agent's Stage A prompt to
 * surface paramFields + traitNames + inlineTraitNames as the closed
 * set the LLM may emit.
 */
export function getOrbitalFactoryManifest(
  organism: string,
  orbitalName: string,
): OrbitalParamsManifest | null {
  const entry = REGISTRY.get(`${organism}::${orbitalName}`);
  return entry ? entry.manifest : null;
}

/**
 * List every orbital manifest for one organism. Used by Stage A to
 * embed the chosen organism's full manifest set into the prompt.
 */
export function listOrganismOrbitalManifests(
  organism: string,
): OrbitalParamsManifest[] {
  const out: OrbitalParamsManifest[] = [];
  const prefix = `${organism}::`;
  for (const [key, entry] of REGISTRY) {
    if (key.startsWith(prefix)) out.push(entry.manifest);
  }
  return out;
}
